local function is_private_ip(ip)
    if not ip then return true end

    -- IPv4 private/reserved ranges
    local octets = {ip:match("^(%d+)%.(%d+)%.(%d+)%.(%d+)$")}
    if #octets ~= 4 then return true end

    local o1, o2, o3, o4 = tonumber(octets[1]), tonumber(octets[2]), tonumber(octets[3]), tonumber(octets[4])

    -- 0.0.0.0/8
    if o1 == 0 then return true end
    -- 10.0.0.0/8
    if o1 == 10 then return true end
    -- 127.0.0.0/8 (loopback)
    if o1 == 127 then return true end
    -- 169.254.0.0/16 (link-local)
    if o1 == 169 and o2 == 254 then return true end
    -- 172.16.0.0/12
    if o1 == 172 and o2 >= 16 and o2 <= 31 then return true end
    -- 192.168.0.0/16
    if o1 == 192 and o2 == 168 then return true end
    -- 224.0.0.0/4 (multicast)
    if o1 >= 224 and o1 <= 239 then return true end
    -- 240.0.0.0/4 (reserved)
    if o1 >= 240 then return true end
    -- 100.64.0.0/10 (carrier-grade NAT)
    if o1 == 100 and o2 >= 64 and o2 <= 127 then return true end
    -- 192.0.0.0/24
    if o1 == 192 and o2 == 0 and o3 == 0 then return true end
    -- 198.18.0.0/15 (benchmarking)
    if o1 == 198 and (o2 == 18 or o2 == 19) then return true end

    return false
end

